(83, 0, 'RuleDictionnaryOperatingSystem', 1, 'Clean Linux OS Name', '', 'AND', 0, '/(SUSE|SunOS|Red Hat|CentOS|Ubuntu|Debian|Fedora|AlmaLinux|Oracle|Amazon Linux)(?:\\D+|)([\\d.]*) ?(?:\\(?([\\w ]+)\\)?)?/\n\n            Example :\n            Ubuntu 22.04.1 LTS -> #0 = Ubuntu\n            SUSE Linux Enterprise Server 11 (x86_64)  ->#0 = SUSE\n            SunOS -> #0 = SunOS\n            Red Hat Enterprise Linux Server release 7.9 (Maipo) -> #0 = Red Hat\n            Oracle Linux Server release 7.3 -> #0 = Oracle\n            Fedora release 36 (Thirty Six) -> #0 = Fedora\n            Debian GNU/Linux 9.5 (stretch) -> #0 = Debian\n            CentOS Stream release 8 -> #0 = CentOS\n            AlmaLinux 9.0 (Emerald Puma) -> #0 = AlmaLinux\n            Amazon Linux 2023 -> #0 = Amazon Linux', '2026-03-23 10:21:38', 1, 'clean_linux_os_name', 0, '2026-03-23 10:21:38'),
(84, 0, 'RuleDictionnaryOperatingSystem', 2, 'Clean Windows OS Name', '', 'AND', 0, '/(Microsoft)(?>\\(R\\)|®)? (Windows) (XP|\\d\\.\\d|\\d{1,4}|Vista)(™)? ?(.*)/\n\n            Example :\n            Microsoft Windows XP Professionnel -> #1 : Windows\n            Microsoft Windows 7 Enterprise  -> #1 : Windows\n            Microsoft® Windows Vista Professionnel  -> #1 : Windows\n            Microsoft Windows XP Édition familiale  -> #1 : Windows\n            Microsoft Windows 10 Entreprise  -> #1 : Windows\n            Microsoft Windows 10 Professionnel  -> #1 : Windows\n            Microsoft Windows 11 Professionnel  -> #1 : Windows', '2026-03-23 10:21:38', 1, 'clean_windows_os_name', 0, '2026-03-23 10:21:38'),
(85, 0, 'RuleDictionnaryOperatingSystem', 3, 'Clean Windows Server OS Name', '', 'AND', 0, '/(Microsoft)(?>\\(R\\)|®)? (?:(Hyper-V|Windows)(?:\\(R\\))?) ((?:Server|))(?:\\(R\\)|®)? (\\d{4}(?: R2)?)(?:[,\\s]++)?([^\\s]*)(?: Edition(?: x64)?)?$/\n\n            Example :\n            Microsoft Windows Server 2012 R2 Datacenter -> #1 #2 : Windows Server\n            Microsoft(R) Windows(R) Server 2003, Standard Edition x64 -> #1 #2 : Windows Server\n            Microsoft Hyper-V Server 2012 R2 -> #1 #2 : Hyper-V Server\n            Microsoft® Windows Server® 2008 Standard -> #1 #2 : Windows Server', '2026-03-23 10:21:38', 1, 'clean_windows_server_os_name', 0, '2026-03-23 10:21:38'),
(86, 0, 'RuleDictionnaryOperatingSystemVersion', 1, 'Clean Linux OS Version', '', 'AND', 0, '/(SUSE|SunOS|Red Hat|CentOS|Ubuntu|Debian|Fedora|AlmaLinux|Oracle)(?:\\D+|)([\\d.]+) ?(?:\\(?([\\w ]+)\\)?)?/\n\n            Example :\n            Ubuntu 22.04.1 LTS -> #1 = 22.04.1\n            SUSE Linux Enterprise Server 11 (x86_64) -> #1 =  11\n            SunOS 5.10 -> #1 = 5.10\n            Red Hat Enterprise Linux Server release 7.9 (Maipo) -> #1 = 7.9\n            Oracle Linux Server release 7.3 -> #1 = 7.3\n            Fedora release 36 (Thirty Six) -> #1 =  36\n            Debian GNU/Linux 9.5 (stretch) -> #1 = 9.5\n            CentOS release 6.9 (Final) -> #1 = 6.9\n            AlmaLinux 9.0 (Emerald Puma) -> #1 = 9.0', '2026-03-23 10:21:38', 1, 'clean_linux_os_version', 0, '2026-03-23 10:21:38'),
(87, 0, 'RuleDictionnaryOperatingSystemVersion', 2, 'Clean Windows OS Version', '', 'AND', 0, '/(Microsoft)(?>\\(R\\)|®)? (Windows) (XP|\\d\\.\\d|\\d{1,4}|Vista)(™)? ?(.*)/\n\n            Example :\n            Microsoft Windows XP Professionnel -> #2 : XP\n            Microsoft Windows 7 Enterprise  -> #2 : 7\n            Microsoft® Windows Vista Professionnel  -> #2 : Vista\n            Microsoft Windows XP Édition familiale  -> #2 : XP\n            Microsoft Windows 10 Entreprise  -> #2 : 10\n            Microsoft Windows 10 Professionnel  -> #2 : 10\n            Microsoft Windows 11 Professionnel  -> #2 : 11', '2026-03-23 10:21:38', 1, 'clean_windows_os_version', 0, '2026-03-23 10:21:38'),
(88, 0, 'RuleDictionnaryOperatingSystemVersion', 3, 'Clean Windows Server OS Version', '', 'AND', 0, '/(Microsoft)(?>\\(R\\)|®)? (?:(Hyper-V|Windows)(?:\\(R\\))?) ((?:Server|))(?:\\(R\\)|®)? (\\d{4}(?: R2)?)(?:[,\\s]++)?([^\\s]*)(?: Edition(?: x64)?)?$/\n\n            Example :\n            Microsoft Windows Server 2012 R2 Datacenter -> #3 : 2012 R2\n            Microsoft(R) Windows(R) Server 2003, Standard Edition x64 -> #3 : 2003\n            Microsoft Hyper-V Server 2012 R2 -> #3 : 2012 R2\n            Microsoft® Windows Server® 2008 Standard -> #3 : 2008', '2026-03-23 10:21:38', 1, 'clean_windows_server_os_version', 0, '2026-03-23 10:21:38'),
(89, 0, 'RuleDictionnaryOperatingSystemEdition', 1, 'Clean Linux OS Edition', '', 'AND', 0, '/(SUSE|SunOS|Red Hat|CentOS|Ubuntu|Debian|Fedora|AlmaLinux|Oracle)(?:\\D+|)([\\d.]+) ?(?:\\(?([\\w ]+)\\)?)?/\n\n        Example :\n        Ubuntu 22.04.1 LTS -> #2 = LTS\n        SUSE Linux Enterprise Server 11 (x86_64) -> #2 = x86_64\n        Red Hat Enterprise Linux Server release 7.9 (Maipo) -> #2 = Maipo\n        Red Hat Enterprise Linux Server release 6.10 (Santiago) -> #2 = Santiago\n        Fedora release 36 (Thirty Six) -> #2 = Thirty Six\n        Debian GNU/Linux 9.5 (stretch) -> #2 = stretch\n        Debian GNU/Linux 8.9 (jessie) -> #2 = jessie\n        CentOS Linux release 7.2.1511 (Core) -> #2 = Core\n        AlmaLinux 9.0 (Emerald Puma) -> #2 = Emerald Puma\n        AlmaLinux 8.6 (Sky Tiger) -> #2 = Sky Tiger', '2026-03-23 10:21:38', 1, 'clean_linux_os_edition', 0, '2026-03-23 10:21:38'),
(90, 0, 'RuleDictionnaryOperatingSystemEdition', 2, 'Clean Windows OS Edition', '', 'AND', 0, '/(Microsoft)(?>\\(R\\)|®)? (Windows) (XP|\\d\\.\\d|\\d{1,4}|Vista)(™)? ?(.*)/\n\n        Example :\n        Microsoft Windows XP Professionnel -> #4 : Professionnel\n        Microsoft Windows 7 Enterprise  -> #4 : Enterprise\n        Microsoft® Windows Vista Professionnel  -> #4 : Professionnel\n        Microsoft Windows XP Édition familiale  -> #4 : Édition familiale\n        Microsoft Windows 10 Entreprise  -> #4 : Entreprise\n        Microsoft Windows 10 Professionnel  -> #4 : Professionnel\n        Microsoft Windows 11 Professionnel  -> #4 : Professionnel', '2026-03-23 10:21:38', 1, 'clean_windows_os_edition', 0, '2026-03-23 10:21:38'),
(91, 0, 'RuleDictionnaryOperatingSystemEdition', 3, 'Clean Windows Server OS Edition', '', 'AND', 0, '/(Microsoft)(?>\\(R\\)|®)? (?:(Hyper-V|Windows)(?:\\(R\\))?) ((?:Server|))(?:\\(R\\)|®)? (\\d{4}(?: R2)?)(?:[,\\s]++)?([^\\s]*)(?: Edition(?: x64)?)?$/\n\n        Example :\n        Microsoft Windows Server 2012 R2 Datacenter -> #4 : Datacenter\n        Microsoft(R) Windows(R) Server 2003, Standard Edition x64 -> #4 : Standard\n        Microsoft Hyper-V Server 2012 R2 -> #4 :\n        Microsoft® Windows Server® 2008 Standard -> #4: Standard', '2026-03-23 10:21:38', 1, 'clean_windows_server_os_edition', 0, '2026-03-23 10:21:38');

